sql:
SELECT user_id, SUM(amount) AS total_spent
FROM in_game_purchases
GROUP BY user_id;

SELECT game_id, COUNT(*) AS total_downloads, AVG(download_speed) AS average_download_speed
FROM game_downloads
GROUP BY game_id;

SELECT SUM(amount) AS total_spent
FROM in_game_purchases
WHERE game_id = 1;

SELECT game_id, SUM(impressions) AS total_impressions, SUM(ad_cost) AS total_ad_cost
FROM game_ads
GROUP BY game_id;

SELECT game_id, ad_type, ad_cost
FROM game_ads
WHERE clicks >= 1;

SELECT SUM(amount) AS total_spent
FROM in_game_purchases
WHERE game_id = 1;

SELECT rating
FROM games
ORDER BY rating DESC;

SELECT total_playtime
FROM game_engagement
WHERE game_id = 1;

SELECT user_id, SUM(playtime) as total_playtime
FROM user_games
GROUP BY user_id;

SELECT item_name, item_type
FROM in_game_purchases
WHERE amount > 5;

SELECT playtime, level, achievements
FROM user_games
WHERE user_id = 0 AND game_id = 0;

SELECT AVG(rating) AS avg_rating
FROM user_reviews
WHERE game_id = 0;
